example_bad:
trait Greet {
    fn hello(&self);
}

struct Person;

impl Greet for Person {
    fn hello(&self) { println!("Hi!"); }
}

impl Greet for Person { // Error: conflicting implementation
    fn hello(&self) { println!("Hey!"); }
}

fixes.code:
impl Greet for Person {
    fn hello(&self) { println!("Hi!"); }
}
// Remove the second impl

struct FormalPerson;
struct CasualPerson;

impl Greet for FormalPerson {
    fn hello(&self) { println!("Good day!"); }
}
impl Greet for CasualPerson {
    fn hello(&self) { println!("Hey!"); }
}
